code = """import json
import datetime

# Load data from database queries
closed_cases = locals()['var_functions.query_db:28']
owner_data = locals()['var_functions.query_db:36']

# Build owner lookup dictionary
owner_lookup = {}
for record in owner_data:
    owner_lookup[record['caseid__c']] = record['newvalue__c']

# Calculate handle times and group by agent
cases_by_agent = {}

for case in closed_cases:
    case_id = case['id'].lstrip('#')
    created_str = case['createddate']
    closed_str = case['closeddate']
    
    # Skip if missing data
    if not case_id or not created_str or not closed_str or closed_str == 'None':
        continue
    
    # Get owner from casehistory
    owner_id = owner_lookup.get(case_id)
    if not owner_id:
        continue
    
    try:
        # Parse dates
        created = datetime.datetime.fromisoformat(created_str.replace('Z', '+00:00'))
        closed = datetime.datetime.fromisoformat(closed_str.replace('Z', '+00:00'))
        
        # Calculate handle time in minutes
        handle_time = int((closed - created).total_seconds() / 60)
        
        if handle_time > 0:
            if owner_id not in cases_by_agent:
                cases_by_agent[owner_id] = []
            cases_by_agent[owner_id].append(handle_time)
            
    except:
        continue

# Calculate average handle time for agents with more than 1 case
agent_averages = []
for agent_id, handle_times in cases_by_agent.items():
    if len(handle_times) > 1:
        avg_time = sum(handle_times) / len(handle_times)
        agent_averages.append({
            'agent_id': agent_id,
            'case_count': len(handle_times),
            'avg_handle_time': avg_time
        })

# Sort by average handle time (lowest first)
agent_averages.sort(key=lambda x: x['avg_handle_time'])

result = None
if agent_averages:
    best = agent_averages[0]
    result = {
        'agent_id': best['agent_id'],
        'avg_handle_time': round(best['avg_handle_time'], 2),
        'case_count': best['case_count']
    }
    print("Best agent: %s with avg %.2f minutes" % (best['agent_id'], best['avg_handle_time']))
else:
    print("No agents with more than 1 case found")

print('__RESULT__:')
print(json.dumps(result) if result else json.dumps({'error': 'No results'}))"""

